class Solution {
    public int countLargestGroup(int n) {
        int[] groups = new int[10];
        int count = 0;
        for (int i = 1; i <= n; i++) {
            int sum = 0;
            while (i > 1) {
                sum += i % 10;
                i /= 10;
            }
            groups[sum]++;
        }
        for (int sum = 1; sum <= 9; sum++) {
            int count = groups[sum];
            groups[sum] = 0;
            for (int i = 1; i <= n; i++) {
                int sum = 0;
                while (i > 1) {
                    sum += i % 10;
                    i /= 10;
                }
                if (groups[sum] == 0) {
                    groups[sum]++;
                }
            }
            int maxCount = 0;
            for (int count = 1; count <= n; count++) {
                int sum = 0;
                while (count > 1) {
                    sum += count % 10;
                    count /= 10;
                }
                if (groups[sum] == 0) {
                    groups[sum]++;
                }
            }
            maxCount = Math.max(maxCount, groups[sum]);
        }
        return maxCount;
    }
}
